design.sql_ddl:
-- Description: Tracks various campaigns run by the PR department.
CREATE TABLE CAMPAIGN (
    id uuid PRIMARY KEY, -- SRS: 1.1.1
    name string NOT NULL, -- SRS: 1.1.1
    media_channel string NOT NULL, -- SRS: 1.1.2
    location string NOT NULL -- SRS: 1.1.3
);
CREATE INDEX idx_campaign_name ON CAMPAIGN(name);

-- Description: Stores details of prospective students.
CREATE TABLE PROSPECTIVE_STUDENT (
    id uuid PRIMARY KEY, -- SRS: 1.4.3
    name string NOT NULL, -- SRS: 1.4.3
    email string NOT NULL UNIQUE, -- SRS: 1.4.3
    mobile_number string NOT NULL, -- SRS: 1.4.20
    address string NOT NULL, -- SRS: 1.4.3
    is_parent_employee boolean NOT NULL, -- SRS: 1.4.3
    enquiry_id uuid NOT NULL UNIQUE -- SRS: 1.4.1
);
CREATE INDEX idx_prospective_student_email ON PROSPECTIVE_STUDENT(email);

-- Description: Records admission applications from prospective students.
CREATE TABLE ADMISSION_APPLICATION (
    id uuid PRIMARY KEY, -- SRS: 1.4.6
    prospective_student_id uuid NOT NULL REFERENCES PROSPECTIVE_STUDENT(id), -- SRS: 1.4.6
    campaign_id uuid NOT NULL REFERENCES CAMPAIGN(id), -- SRS: 1.4.2
    status string CHECK (status IN ('Accept', 'Reject', 'Cancelled')), -- SRS: 1.4.9
    registration_number string NOT NULL UNIQUE, -- SRS: 1.4.18
    application_date timestamp NOT NULL -- SRS: 1.4.6
);
CREATE INDEX idx_admission_application_registration_number ON ADMISSION_APPLICATION(registration_number);

-- Description: Records details of enquiries made by prospective students.
CREATE TABLE ADMISSION_ENQUIRY (
    id uuid PRIMARY KEY, -- SRS: 1.4.1
    prospective_student_id uuid NOT NULL REFERENCES PROSPECTIVE_STUDENT(id), -- SRS: 1.4.1
    program_of_interest string NOT NULL, -- SRS: 1.4.2
    batch_of_interest string NOT NULL -- SRS: 1.4.2
);
CREATE INDEX idx_admission_enquiry_prospective_student_id ON ADMISSION_ENQUIRY(prospective_student_id);

-- Description: Stores merit list details for admission applications.
CREATE TABLE MERIT_LIST (
    id uuid PRIMARY KEY, -- SRS: 1.4.10
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: 1.4.10
    rank integer NOT NULL -- SRS: 1.4.10
);
CREATE INDEX idx_merit_list_admission_application_id ON MERIT_LIST(admission_application_id);

-- Description: Stores documents submitted during the admission process.
CREATE TABLE DOCUMENT (
    id uuid PRIMARY KEY, -- SRS: 1.5.3
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: 1.5.3
    document_type string NOT NULL, -- SRS: 1.5.3
    is_verified boolean NOT NULL -- SRS: 1.5.3
);
CREATE INDEX idx_document_admission_application_id ON DOCUMENT(admission_application_id);

-- Description: Records confirmation of admission for students.
CREATE TABLE ADMISSION_CONFIRMATION (
    id uuid PRIMARY KEY, -- SRS: 1.4.15
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: 1.4.15
    is_confirmed boolean NOT NULL, -- SRS: 1.4.15
    confirmation_date timestamp NOT NULL -- SRS: 1.4.15
);
CREATE INDEX idx_admission_confirmation_admission_application_id ON ADMISSION_CONFIRMATION(admission_application_id);

-- Description: Records cancellation of admission applications.
CREATE TABLE ADMISSION_CANCELLATION (
    id uuid PRIMARY KEY, -- SRS: 1.4.17
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: 1.4.17
    reason string NOT NULL, -- SRS: 1.4.17
    cancellation_date timestamp NOT NULL -- SRS: 1.4.17
);
CREATE INDEX idx_admission_cancellation_admission_application_id ON ADMISSION_CANCELLATION(admission_application_id);

-- Description: Records follow-up actions for admission applications.
CREATE TABLE ADMISSION_FOLLOW_UP (
    id uuid PRIMARY KEY, -- SRS: 1.4.4
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: 1.4.4
    follow_up_notes string NOT NULL, -- SRS: 1.4.4
    follow_up_date timestamp NOT NULL -- SRS: 1.4.4
);
CREATE INDEX idx_admission_follow_up_admission_application_id ON ADMISSION_FOLLOW_UP(admission_application_id);

-- Description: Junction table to handle many-to-many relationship between prospective students and their programs and batches of interest.
CREATE TABLE PROSPECTIVE_STUDENT_PROGRAM_BATCH (
    id uuid PRIMARY KEY, -- SRS: New junction table for many-to-many relationship
    prospective_student_id uuid NOT NULL REFERENCES PROSPECTIVE_STUDENT(id), -- SRS: Links to prospective student
    program_of_interest string NOT NULL, -- SRS: Records program of interest
    batch_of_interest string NOT NULL -- SRS: Records batch of interest
);
CREATE INDEX idx_prospective_student_program_batch ON PROSPECTIVE_STUDENT_PROGRAM_BATCH(id);

-- Description: Handles the transformation of pre-admission records to post-admission.
CREATE TABLE ADMISSION_RECORD_TRANSFORMATION (
    id uuid PRIMARY KEY, -- SRS: New table for managing record transformation
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: Links to the admission application being transformed
    transformation_date timestamp NOT NULL, -- SRS: Records the date of transformation
    status string CHECK (status IN ('Pre-Admission', 'Post-Admission')) -- SRS: Indicates the current status of the record
);
CREATE INDEX idx_admission_record_transformation_application_id ON ADMISSION_RECORD_TRANSFORMATION(id);

-- Description: Manages the admission process including round creation, reporting, document verification, fees submission, branch allotment, and final confirmation.
CREATE TABLE ADMISSION_PROCESS (
    id uuid PRIMARY KEY, -- SRS: New table for managing the admission process
    admission_application_id uuid NOT NULL REFERENCES ADMISSION_APPLICATION(id), -- SRS: Links to the admission application
    round_number integer NOT NULL, -- SRS: Indicates the round of admission
    document_verified boolean NOT NULL, -- SRS: Indicates if documents have been verified
    fees_submitted boolean NOT NULL, -- SRS: Indicates if fees have been submitted
    branch_allotted string NOT NULL, -- SRS: Records the branch allotted to the student
    final_confirmation boolean NOT NULL, -- SRS: Indicates if the admission is confirmed
    created_at timestamp NOT NULL -- SRS: Records the creation date of the admission process entry
);
CREATE INDEX idx_admission_process_application_id ON ADMISSION_PROCESS(id);

