design.sql_ddl:
-- Description: Stores the master setup for fees including receipt type, fees head, payment category, and standard fees.
CREATE TABLE fees_master (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each fee master entry.
    receipt_type string NOT NULL, -- SRS: Defines the type of receipt for the fee.
    fees_head string NOT NULL, -- SRS: Specifies the head under which the fee is categorized.
    payment_category string NOT NULL, -- SRS: Categorizes the payment type for the fee.
    standard_fees decimal NOT NULL CHECK (standard_fees >= 0) -- SRS: Defines the standard fee amount.
);
CREATE INDEX idx_fees_head ON fees_master(fees_head);

-- Description: Stores student information.
CREATE TABLE student (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each student.
    name string NOT NULL, -- SRS: Full name of the student.
    email string NOT NULL UNIQUE, -- SRS: Email address of the student.
    phone string NOT NULL -- SRS: Contact number of the student.
);
CREATE INDEX idx_student_email ON student(email);

-- Description: Links students to their fee plans.
CREATE TABLE fee_plan (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each fee plan.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student enrolled in the fee plan.
    fees_master_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee master setup for the plan.
    enrollment_date date NOT NULL -- SRS: Date when the student enrolled in the fee plan.
);
CREATE INDEX idx_student_fee_plan ON fee_plan(id);

-- Description: Records fee payment receipts.
CREATE TABLE receipt (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each receipt.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student who made the payment.
    fees_master_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee master setup for the payment.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Amount paid in the receipt.
    receipt_date date NOT NULL, -- SRS: Date when the payment was made.
    status string NOT NULL CHECK (status IN ('Paid', 'Pending', 'Cancelled')) -- SRS: Status of the receipt.
);
CREATE INDEX idx_receipt_student ON receipt(id);

-- Description: Records refund transactions for receipts.
CREATE TABLE refund (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each refund.
    receipt_id uuid NOT NULL REFERENCES receipt(id), -- SRS: References the receipt for which the refund is issued.
    refund_amount decimal NOT NULL CHECK (refund_amount >= 0), -- SRS: Amount refunded to the student.
    refund_date date NOT NULL, -- SRS: Date when the refund was processed.
    reason string NOT NULL -- SRS: Reason for the refund.
);
CREATE INDEX idx_refund_receipt ON refund(id);

-- Description: Records scholarship details for students.
CREATE TABLE scholarship (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each scholarship entry.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student receiving the scholarship.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Amount of the scholarship awarded.
    awarded_date date NOT NULL, -- SRS: Date when the scholarship was awarded.
    description string NOT NULL -- SRS: Description of the scholarship.
);
CREATE INDEX idx_scholarship_student ON scholarship(id);

-- Description: Records write-off entries for fees.
CREATE TABLE write_off (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each write-off entry.
    fees_master_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee master setup for the write-off.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Amount written off.
    write_off_date date NOT NULL, -- SRS: Date when the write-off was processed.
    reason string NOT NULL -- SRS: Reason for the write-off.
);
CREATE INDEX idx_write_off_fees ON write_off(id);

-- Description: Records fund transfers between fee heads.
CREATE TABLE fund_transfer (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each fund transfer.
    from_fees_head uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee head from which funds are transferred.
    to_fees_head uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee head to which funds are transferred.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Amount transferred.
    transfer_date date NOT NULL -- SRS: Date when the transfer was made.
);
CREATE INDEX idx_fund_transfer ON fund_transfer(id);

-- Description: Stores daily collection reports.
CREATE TABLE daily_collection_report (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each report.
    report_date date NOT NULL, -- SRS: Date of the report.
    total_collected decimal NOT NULL CHECK (total_collected >= 0), -- SRS: Total amount collected on the report date.
    total_outstanding decimal NOT NULL CHECK (total_outstanding >= 0) -- SRS: Total outstanding amount on the report date.
);
CREATE INDEX idx_daily_collection_report ON daily_collection_report(id);

-- Description: Maintains a ledger for each student.
CREATE TABLE student_ledger (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each ledger entry.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student for whom the ledger is maintained.
    total_due decimal NOT NULL CHECK (total_due >= 0), -- SRS: Total amount due from the student.
    total_paid decimal NOT NULL CHECK (total_paid >= 0), -- SRS: Total amount paid by the student.
    last_updated date NOT NULL -- SRS: Date when the ledger was last updated.
);
CREATE INDEX idx_student_ledger ON student_ledger(id);

-- Description: Stores clearance amount updates made by admin.
CREATE TABLE clearance_amount (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each clearance amount entry.
    admin_id uuid NOT NULL REFERENCES admin(id), -- SRS: References the admin who updated the clearance amount.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: The updated clearance amount.
    update_date date NOT NULL -- SRS: Date when the clearance amount was updated.
);
CREATE INDEX idx_clearance_amount_admin ON clearance_amount(amount);

-- Description: Manages duplicate receipt handling.
CREATE TABLE duplicate_receipt_handling (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each duplicate receipt entry.
    receipt_id uuid NOT NULL REFERENCES receipt(id), -- SRS: References the original receipt that is duplicated.
    duplicate_receipt_date date NOT NULL, -- SRS: Date when the duplicate receipt was created.
    reason string NOT NULL -- SRS: Reason for handling the duplicate receipt.
);
CREATE INDEX idx_duplicate_receipt ON duplicate_receipt_handling(id);

-- Description: Handles demand generation for fees.
CREATE TABLE demand_generation (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each demand generation entry.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student for whom the demand is generated.
    fees_master_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee master setup for the demand.
    demand_amount decimal NOT NULL CHECK (demand_amount >= 0), -- SRS: Amount of fees demanded.
    demand_date date NOT NULL -- SRS: Date when the demand was generated.
);
CREATE INDEX idx_demand_generation ON demand_generation(id);

-- Description: Manages invoicing for sponsored and student payments.
CREATE TABLE sponsored_student_invoicing (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each invoicing entry.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student for whom the invoice is generated.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the invoice.
    invoice_date date NOT NULL, -- SRS: Date when the invoice was created.
    sponsor_details string NOT NULL -- SRS: Details of the sponsor for the invoice.
);
CREATE INDEX idx_sponsored_student_invoicing ON sponsored_student_invoicing(id);

-- Description: Manages discounts on exam fees for identified students.
CREATE TABLE exam_fee_discounts (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each discount entry.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: References the student receiving the discount.
    discount_amount decimal NOT NULL CHECK (discount_amount >= 0), -- SRS: Amount of discount applied.
    exam_fee_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the exam fee to which the discount applies.
    discount_date date NOT NULL -- SRS: Date when the discount was applied.
);
CREATE INDEX idx_exam_fee_discounts ON exam_fee_discounts(id);

-- Description: Handles integration with Tally for financial transactions.
CREATE TABLE tally_integration (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each Tally integration entry.
    transaction_id uuid NOT NULL, -- SRS: Identifier for the transaction being integrated.
    tally_status string NOT NULL, -- SRS: Status of the transaction in Tally.
    integration_date date NOT NULL, -- SRS: Date when the integration occurred.
    error_message string NULL -- SRS: Error message if the integration fails.
);
CREATE INDEX idx_tally_integration ON tally_integration(id);

-- Description: Stores rules for processing refunds.
CREATE TABLE refund_rule (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each refund rule.
    rule_description string NOT NULL, -- SRS: Description of the refund processing rule.
    created_date date NOT NULL -- SRS: Date when the refund rule was created.
);
CREATE INDEX idx_refund_rule_description ON refund_rule(rule_description);

-- Description: Stores fee head-wise collection summary reports.
CREATE TABLE fee_collection_summary (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each collection summary entry.
    fees_head string NOT NULL, -- SRS: Specifies the head under which the fee is categorized.
    total_collected decimal NOT NULL CHECK (total_collected >= 0), -- SRS: Total amount collected under the specified fee head.
    report_date date NOT NULL -- SRS: Date of the collection report.
);
CREATE INDEX idx_fee_collection_summary_fees_head ON fee_collection_summary(fees_head);

-- Description: Links fees with academic and exam activities.
CREATE TABLE academic_exam_fee_link (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each link entry.
    fees_master_id uuid NOT NULL REFERENCES fees_master(id), -- SRS: References the fee master setup linked to academic or exam activities.
    activity_type string NOT NULL, -- SRS: Type of activity (e.g., academic, exam).
    activity_id uuid NOT NULL -- SRS: Identifier for the specific academic or exam activity.
);
CREATE INDEX idx_academic_exam_fee_link_activity ON academic_exam_fee_link(id);

