design.sql_ddl:
-- Description: Table to store course details.
CREATE TABLE course (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each course.
    name string NOT NULL, -- SRS: Name of the course.
    syllabus string NOT NULL, -- SRS: Syllabus for the course.
    credits integer NOT NULL CHECK (credits > 0), -- SRS: Credits assigned to the course.
    objectives string NOT NULL, -- SRS: Objectives of the course.
    outcomes string NOT NULL -- SRS: Expected outcomes of the course.
);
CREATE INDEX idx_course_name ON course(name);

-- Description: Table to store student details.
CREATE TABLE student (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each student.
    name string NOT NULL, -- SRS: Name of the student.
    email string NOT NULL UNIQUE, -- SRS: Email of the student.
    registration_number string NOT NULL UNIQUE -- SRS: Registration number of the student.
);
CREATE INDEX idx_student_email ON student(email);

-- Description: Table to store faculty details.
CREATE TABLE faculty (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each faculty member.
    name string NOT NULL, -- SRS: Name of the faculty member.
    email string NOT NULL UNIQUE, -- SRS: Email of the faculty member.
    department string NOT NULL -- SRS: Department of the faculty member.
);
CREATE INDEX idx_faculty_email ON faculty(email);

-- Description: Table to store class details.
CREATE TABLE class (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each class.
    name string NOT NULL, -- SRS: Name of the class.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Foreign key referencing the course.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty.
);
CREATE INDEX idx_class_course_id ON class(course_id);
CREATE INDEX idx_class_faculty_id ON class(faculty_id);

-- Description: Table to store attendance records.
CREATE TABLE attendance (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance record.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Foreign key referencing the student.
    class_id uuid NOT NULL REFERENCES class(id), -- SRS: Foreign key referencing the class.
    present boolean NOT NULL, -- SRS: Indicates if the student was present.
    date date NOT NULL -- SRS: Date of the attendance record.
);
CREATE INDEX idx_attendance_student_id ON attendance(student_id);
CREATE INDEX idx_attendance_class_id ON attendance(class_id);

-- Description: Table to store exam details.
CREATE TABLE exam (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each exam.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Foreign key referencing the course.
    exam_date date NOT NULL, -- SRS: Date of the exam.
    type string NOT NULL -- SRS: Type of the exam (e.g., Midterm, Final).
);
CREATE INDEX idx_exam_course_id ON exam(course_id);

-- Description: Table to store grades for students.
CREATE TABLE grade (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each grade record.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Foreign key referencing the student.
    exam_id uuid NOT NULL REFERENCES exam(id), -- SRS: Foreign key referencing the exam.
    marks float NOT NULL CHECK (marks >= 0), -- SRS: Marks obtained by the student.
    grade string NOT NULL -- SRS: Grade awarded to the student.
);
CREATE INDEX idx_grade_student_id ON grade(student_id);
CREATE INDEX idx_grade_exam_id ON grade(exam_id);

-- Description: Table to store course registration details.
CREATE TABLE course_registration (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each registration.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Foreign key referencing the student.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Foreign key referencing the course.
    status string NOT NULL CHECK (status IN ('Registered', 'Dropped', 'Completed')) -- SRS: Status of the registration.
);
CREATE INDEX idx_course_registration_student_id ON course_registration(student_id);
CREATE INDEX idx_course_registration_course_id ON course_registration(course_id);

-- Description: Table to store feedback from students.
CREATE TABLE feedback (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each feedback record.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Foreign key referencing the course.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Foreign key referencing the student.
    comments string NOT NULL, -- SRS: Comments provided by the student.
    rating integer NOT NULL CHECK (rating >= 1 AND rating <= 5) -- SRS: Rating given by the student.
);
CREATE INDEX idx_feedback_course_id ON feedback(course_id);
CREATE INDEX idx_feedback_student_id ON feedback(student_id);

-- Description: Table to store detailed academic calendar information.
CREATE TABLE academic_calendar (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each academic calendar entry.
    start_date date NOT NULL, -- SRS: Start date of the academic term.
    end_date date NOT NULL, -- SRS: End date of the academic term.
    term string NOT NULL, -- SRS: Term of the academic calendar.
    instructional_days integer NOT NULL CHECK (instructional_days > 0), -- SRS: Number of instructional days in the term.
    contact_hours_per_week integer NOT NULL CHECK (contact_hours_per_week > 0) -- SRS: Number of contact hours per week.
);
CREATE INDEX idx_academic_calendar_term ON academic_calendar(term);

-- Description: Table to store timetable details.
CREATE TABLE timetable (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each timetable entry.
    class_id uuid NOT NULL REFERENCES class(id), -- SRS: Foreign key referencing the class.
    date date NOT NULL, -- SRS: Date of the class.
    time_slot string NOT NULL -- SRS: Time slot for the class.
);
CREATE INDEX idx_timetable_class_id ON timetable(class_id);

-- Description: Table to store project details.
CREATE TABLE project (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each project.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Foreign key referencing the student.
    title string NOT NULL, -- SRS: Title of the project.
    description string NOT NULL, -- SRS: Description of the project.
    submission_date date NOT NULL -- SRS: Submission date of the project.
);
CREATE INDEX idx_project_student_id ON project(student_id);

-- Description: Table to store seminar details.
CREATE TABLE seminar (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each seminar.
    title string NOT NULL, -- SRS: Title of the seminar.
    date date NOT NULL, -- SRS: Date of the seminar.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty.
);
CREATE INDEX idx_seminar_faculty_id ON seminar(faculty_id);

-- Description: Table to store workshop details.
CREATE TABLE workshop (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each workshop.
    title string NOT NULL, -- SRS: Title of the workshop.
    date date NOT NULL, -- SRS: Date of the workshop.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty.
);
CREATE INDEX idx_workshop_faculty_id ON workshop(faculty_id);

-- Description: Table to store industry visit details.
CREATE TABLE industry_visit (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each industry visit.
    company_name string NOT NULL, -- SRS: Name of the company visited.
    visit_date date NOT NULL, -- SRS: Date of the industry visit.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty.
);
CREATE INDEX idx_industry_visit_faculty_id ON industry_visit(faculty_id);

-- Description: Table to store guest lecture details.
CREATE TABLE guest_lecture (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each guest lecture.
    topic string NOT NULL, -- SRS: Topic of the guest lecture.
    lecture_date date NOT NULL, -- SRS: Date of the guest lecture.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty.
);
CREATE INDEX idx_guest_lecture_faculty_id ON guest_lecture(faculty_id);

-- Description: Table to store evaluation procedures for courses.
CREATE TABLE evaluation_procedure (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each evaluation procedure.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Foreign key referencing the course.
    evaluation_type string NOT NULL, -- SRS: Type of evaluation (e.g., Midterm, Final, Project).
    weightage float NOT NULL CHECK (weightage >= 0 AND weightage <= 100), -- SRS: Weightage of the evaluation in the overall grading.
    description string NOT NULL -- SRS: Description of the evaluation procedure.
);
CREATE INDEX idx_evaluation_procedure_course_id ON evaluation_procedure(course_id);

-- Description: Table to manage various academic activities.
CREATE TABLE academic_activity (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each academic activity.
    activity_type string NOT NULL, -- SRS: Type of academic activity (e.g., Workshop, Seminar, Industry Visit).
    title string NOT NULL, -- SRS: Title of the academic activity.
    date date NOT NULL, -- SRS: Date of the academic activity.
    faculty_id uuid NOT NULL REFERENCES faculty(id) -- SRS: Foreign key referencing the faculty responsible for the activity.
);
CREATE INDEX idx_academic_activity_faculty_id ON academic_activity(faculty_id);

