design.sql_ddl:
-- Description: Stores the schedule for classes, including faculty and room assignments.
CREATE TABLE timetable (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each timetable entry.
    course_id uuid NOT NULL REFERENCES course(id), -- SRS: Links to the course being taught.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Links to the faculty assigned to the class.
    room_id uuid NOT NULL REFERENCES room(id), -- SRS: Links to the room where the class is held.
    start_time timestamp NOT NULL, -- SRS: Start time of the class.
    end_time timestamp NOT NULL, -- SRS: End time of the class.
    type string CHECK (type IN ('Lecture', 'Practical', 'Seminar')), -- SRS: Type of the class.
    status string CHECK (status IN ('Scheduled', 'Cancelled', 'Completed')) -- SRS: Current status of the timetable entry.
);
CREATE INDEX idx_timetable_course ON timetable(id);
CREATE INDEX idx_timetable_faculty ON timetable(id);
CREATE INDEX idx_timetable_room ON timetable(id);

-- Description: Stores information about courses offered.
CREATE TABLE course (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each course.
    name string NOT NULL, -- SRS: Name of the course.
    description string -- SRS: Description of the course.
);
CREATE INDEX idx_course_name ON course(name);

-- Description: Stores information about faculty members.
CREATE TABLE faculty (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each faculty member.
    name string NOT NULL, -- SRS: Name of the faculty member.
    email string UNIQUE -- SRS: Email address of the faculty member.
);
CREATE INDEX idx_faculty_email ON faculty(email);

-- Description: Stores information about rooms available for classes.
CREATE TABLE room (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each room.
    room_number string NOT NULL, -- SRS: Room number.
    building string NOT NULL -- SRS: Building where the room is located.
);
CREATE INDEX idx_room_number ON room(room_number);

-- Description: Records attendance for extra lectures and practicals conducted by substitute faculty.
CREATE TABLE attendance_extra_lectures (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance record.
    timetable_id uuid NOT NULL REFERENCES timetable(id), -- SRS: Links to the timetable entry for the extra lecture or practical.
    student_id uuid NOT NULL REFERENCES student(id), -- SRS: Links to the student attending the extra lecture or practical.
    attendance_status string CHECK (attendance_status IN ('Present', 'Absent')), -- SRS: Records whether the student was present or absent.
    date timestamp NOT NULL -- SRS: Date of the extra lecture or practical.
);
CREATE INDEX idx_attendance_extra_lectures_timetable ON attendance_extra_lectures(id);
CREATE INDEX idx_attendance_extra_lectures_student ON attendance_extra_lectures(id);

-- Description: Stores information about students.
CREATE TABLE STUDENT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each student.
    name string NOT NULL, -- SRS: Name of the student.
    email string UNIQUE NOT NULL, -- SRS: Email address of the student.
    registration_number string UNIQUE NOT NULL -- SRS: Unique registration number for the student.
);
CREATE INDEX idx_student_email ON STUDENT(email);

-- Description: Stores information about courses offered.
CREATE TABLE COURSE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each course.
    name string NOT NULL, -- SRS: Name of the course.
    code string UNIQUE NOT NULL, -- SRS: Unique code for the course.
    credits integer NOT NULL CHECK (credits > 0) -- SRS: Number of credits assigned to the course.
);
CREATE INDEX idx_course_code ON COURSE(code);

-- Description: Stores information about course sections.
CREATE TABLE SECTION (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each section.
    name string NOT NULL, -- SRS: Name of the section.
    course_id uuid NOT NULL REFERENCES COURSE(id) -- SRS: Foreign key referencing the course.
);
CREATE INDEX idx_section_course_id ON SECTION(course_id);

-- Description: Records attendance for students in sections.
CREATE TABLE ATTENDANCE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance record.
    student_id uuid NOT NULL REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    section_id uuid NOT NULL REFERENCES SECTION(id), -- SRS: Foreign key referencing the section.
    attendance_date date NOT NULL, -- SRS: Date of the attendance record.
    status enum NOT NULL CHECK (status IN ('Present', 'Absent', 'Late')), -- SRS: Status of the student's attendance.
    marks integer CHECK (marks >= 0) -- SRS: Marks awarded for attendance.
);
CREATE INDEX idx_attendance_student_id ON ATTENDANCE(student_id);
CREATE INDEX idx_attendance_section_id ON ATTENDANCE(section_id);

-- Description: Stores information about faculty members.
CREATE TABLE FACULTY (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each faculty member.
    name string NOT NULL, -- SRS: Name of the faculty member.
    email string UNIQUE NOT NULL -- SRS: Email address of the faculty member.
);
CREATE INDEX idx_faculty_email ON FACULTY(email);

-- Description: Records extra lectures conducted by faculty.
CREATE TABLE EXTRA_LECTURE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each extra lecture.
    faculty_id uuid NOT NULL REFERENCES FACULTY(id), -- SRS: Foreign key referencing the faculty member.
    section_id uuid NOT NULL REFERENCES SECTION(id), -- SRS: Foreign key referencing the section.
    lecture_date date NOT NULL, -- SRS: Date of the extra lecture.
    topic string NOT NULL -- SRS: Topic covered in the extra lecture.
);
CREATE INDEX idx_extra_lecture_faculty_id ON EXTRA_LECTURE(faculty_id);
CREATE INDEX idx_extra_lecture_section_id ON EXTRA_LECTURE(section_id);

-- Description: Stores attendance reports for sections.
CREATE TABLE ATTENDANCE_REPORT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance report.
    section_id uuid NOT NULL REFERENCES SECTION(id), -- SRS: Foreign key referencing the section.
    report_date date NOT NULL, -- SRS: Date of the attendance report.
    total_present integer NOT NULL CHECK (total_present >= 0), -- SRS: Total number of students present.
    total_absent integer NOT NULL CHECK (total_absent >= 0) -- SRS: Total number of students absent.
);
CREATE INDEX idx_attendance_report_section_id ON ATTENDANCE_REPORT(section_id);

-- Description: Records attendance for students in extra lectures.
CREATE TABLE EXTRA_LECTURE_ATTENDANCE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each extra lecture attendance record.
    attendance_id uuid NOT NULL REFERENCES ATTENDANCE(id), -- SRS: Foreign key referencing the attendance record.
    extra_lecture_id uuid NOT NULL REFERENCES EXTRA_LECTURE(id), -- SRS: Foreign key referencing the extra lecture.
    approval_status enum CHECK (approval_status IN ('Pending', 'Approved', 'Rejected')) -- SRS: Status of attendance approval by the MIS Head.
);
CREATE INDEX idx_extra_lecture_attendance_extra_lecture_id ON EXTRA_LECTURE_ATTENDANCE(extra_lecture_id);

-- Description: Records attendance for students in audit courses.
CREATE TABLE AUDIT_COURSE_ATTENDANCE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each audit course attendance record.
    attendance_id uuid NOT NULL REFERENCES ATTENDANCE(id), -- SRS: Foreign key referencing the attendance record.
    course_id uuid NOT NULL REFERENCES COURSE(id) -- SRS: Foreign key referencing the audit course.
);
CREATE INDEX idx_audit_course_attendance_course_id ON AUDIT_COURSE_ATTENDANCE(course_id);

-- Description: Records attendance approval by the MIS Head for lagging attendance.
CREATE TABLE ATTENDANCE_APPROVAL (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance approval record.
    attendance_id uuid NOT NULL REFERENCES ATTENDANCE(id), -- SRS: Foreign key referencing the attendance record.
    approval_status enum CHECK (approval_status IN ('Pending', 'Approved', 'Rejected')), -- SRS: Status of attendance approval by the MIS Head.
    approval_date date NOT NULL -- SRS: Date when the attendance was approved.
);
CREATE INDEX idx_attendance_approval_attendance_id ON ATTENDANCE_APPROVAL(attendance_id);

