design.sql_ddl:
-- Description: Stores information about students.
CREATE TABLE STUDENT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each student.
    name string NOT NULL, -- SRS: Name of the student.
    registration_number string UNIQUE NOT NULL, -- SRS: Unique registration number for each student.
    email string UNIQUE NOT NULL, -- SRS: Email address of the student.
    phone string NOT NULL -- SRS: Contact number of the student.
);
CREATE INDEX idx_student_registration_number ON STUDENT(registration_number);

-- Description: Stores details of examinations.
CREATE TABLE EXAMINATION (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each examination.
    exam_name string NOT NULL, -- SRS: Name of the examination.
    exam_date date NOT NULL, -- SRS: Date of the examination.
    exam_center_id uuid REFERENCES EXAM_CENTER(id) -- SRS: Foreign key referencing the exam center.
);
CREATE INDEX idx_examination_exam_name ON EXAMINATION(exam_name);

-- Description: Stores information about exam centers.
CREATE TABLE EXAM_CENTER (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each exam center.
    center_name string NOT NULL, -- SRS: Name of the exam center.
    address string NOT NULL -- SRS: Address of the exam center.
);
CREATE INDEX idx_exam_center_name ON EXAM_CENTER(center_name);

-- Description: Stores hall ticket information for students.
CREATE TABLE HALL_TICKET (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each hall ticket.
    student_id uuid REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    ticket_number string UNIQUE NOT NULL -- SRS: Unique ticket number for the hall ticket.
);
CREATE INDEX idx_hall_ticket_ticket_number ON HALL_TICKET(ticket_number);

-- Description: Records attendance for examinations.
CREATE TABLE ATTENDANCE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each attendance record.
    hall_ticket_id uuid REFERENCES HALL_TICKET(id), -- SRS: Foreign key referencing the hall ticket.
    present boolean NOT NULL -- SRS: Indicates if the student was present.
);
CREATE INDEX idx_attendance_hall_ticket_id ON ATTENDANCE(hall_ticket_id);

-- Description: Stores marks for internal and external assessments.
CREATE TABLE MARKS_ENTRY (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each marks entry.
    student_id uuid REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    internal_marks integer NOT NULL CHECK (internal_marks >= 0), -- SRS: Marks obtained in internal assessments.
    external_marks integer NOT NULL CHECK (external_marks >= 0) -- SRS: Marks obtained in external assessments.
);
CREATE INDEX idx_marks_entry_student_id ON MARKS_ENTRY(student_id);

-- Description: Stores grace marks policies for students.
CREATE TABLE GRACE_POLICY (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each grace policy.
    student_id uuid REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    grace_marks integer NOT NULL CHECK (grace_marks >= 0) -- SRS: Number of grace marks awarded.
);
CREATE INDEX idx_grace_policy_student_id ON GRACE_POLICY(student_id);

-- Description: Stores information about invigilators.
CREATE TABLE INVIGILATOR (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each invigilator.
    name string NOT NULL, -- SRS: Name of the invigilator.
    employee_id string UNIQUE NOT NULL -- SRS: Unique employee ID of the invigilator.
);
CREATE INDEX idx_invigilator_employee_id ON INVIGILATOR(employee_id);

-- Description: Stores details of exam papers.
CREATE TABLE EXAM_PAPER (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each exam paper.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    paper_content string NOT NULL -- SRS: Content of the exam paper.
);
CREATE INDEX idx_exam_paper_examination_id ON EXAM_PAPER(examination_id);

-- Description: Stores seating arrangements for students during examinations.
CREATE TABLE SEATING_ARRANGEMENT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each seating arrangement.
    hall_ticket_id uuid REFERENCES HALL_TICKET(id), -- SRS: Foreign key referencing the hall ticket.
    seat_number integer NOT NULL CHECK (seat_number > 0) -- SRS: Seat number assigned to the student.
);
CREATE INDEX idx_seating_arrangement_hall_ticket_id ON SEATING_ARRANGEMENT(hall_ticket_id);

-- Description: Stores the schedule for examinations.
CREATE TABLE EXAM_SCHEDULE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each exam schedule.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    start_time time NOT NULL, -- SRS: Start time of the examination.
    end_time time NOT NULL -- SRS: End time of the examination.
);
CREATE INDEX idx_exam_schedule_examination_id ON EXAM_SCHEDULE(examination_id);

-- Description: Stores information about paper valuers.
CREATE TABLE PAPER_VALUER (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each paper valuer.
    exam_paper_id uuid REFERENCES EXAM_PAPER(id), -- SRS: Foreign key referencing the exam paper.
    invigilator_id uuid REFERENCES INVIGILATOR(id) -- SRS: Foreign key referencing the invigilator.
);
CREATE INDEX idx_paper_valuer_exam_paper_id ON PAPER_VALUER(exam_paper_id);

-- Description: Stores reports of malpractice during examinations.
CREATE TABLE MALPRACTICE_REPORT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each malpractice report.
    student_id uuid REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    details string NOT NULL -- SRS: Details of the malpractice incident.
);
CREATE INDEX idx_malpractice_report_student_id ON MALPRACTICE_REPORT(student_id);

-- Description: Stores information about the printing of mark sheets.
CREATE TABLE MARK_SHEET_PRINTING (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each mark sheet printing record.
    student_id uuid REFERENCES STUDENT(id), -- SRS: Foreign key referencing the student.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    format string NOT NULL, -- SRS: Format in which the mark sheet is printed.
    print_date date NOT NULL -- SRS: Date when the mark sheet was printed.
);
CREATE INDEX idx_mark_sheet_printing_student_id ON MARK_SHEET_PRINTING(student_id);

-- Description: Stores scheduling information for invigilators.
CREATE TABLE INVIGILATOR_SCHEDULE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each invigilator schedule.
    invigilator_id uuid REFERENCES INVIGILATOR(id), -- SRS: Foreign key referencing the invigilator.
    examination_id uuid REFERENCES EXAMINATION(id), -- SRS: Foreign key referencing the examination.
    scheduled_time time NOT NULL, -- SRS: Scheduled time for the invigilator.
    duration integer NOT NULL CHECK (duration > 0) -- SRS: Duration of the invigilation in minutes.
);
CREATE INDEX idx_invigilator_schedule_invigilator_id ON INVIGILATOR_SCHEDULE(invigilator_id);

