design.sql_ddl:
-- Description: Stores information about students applying for internships.
CREATE TABLE STUDENT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each student.
    name string NOT NULL, -- SRS: Student's full name.
    email string UNIQUE NOT NULL, -- SRS: Student's email address.
    phone string NOT NULL, -- SRS: Student's contact number.
    date_of_birth date NOT NULL, -- SRS: Student's date of birth.
    enrollment_number string UNIQUE NOT NULL -- SRS: Unique enrollment number for each student.
);
CREATE INDEX idx_student_email ON STUDENT(email);

-- Description: Stores information about companies offering internships.
CREATE TABLE COMPANY (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each company.
    name string NOT NULL, -- SRS: Company's name.
    industry_type string NOT NULL, -- SRS: Type of industry the company belongs to.
    location string NOT NULL, -- SRS: Company's location.
    contact_person string NOT NULL, -- SRS: Contact person at the company.
    contact_email string NOT NULL, -- SRS: Contact email of the company.
    contact_phone string NOT NULL -- SRS: Contact phone number of the company.
);
CREATE INDEX idx_company_name ON COMPANY(name);

-- Description: Tracks internship applications made by students.
CREATE TABLE INTERNSHIP_REQUEST (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each internship request.
    student_id uuid REFERENCES STUDENT(id) ON DELETE CASCADE, -- SRS: Reference to the student applying for the internship.
    company_id uuid REFERENCES COMPANY(id) ON DELETE CASCADE, -- SRS: Reference to the company offering the internship.
    application_date date NOT NULL, -- SRS: Date when the application was submitted.
    status enum CHECK (status IN ('PENDING', 'APPROVED', 'REJECTED')), -- SRS: Current status of the internship application.
    joining_letter_url string NULL, -- SRS: URL to the joining letter uploaded by the student.
    completion_certificate_url string NULL, -- SRS: URL to the completion certificate uploaded by the student.
    start_date date NULL, -- SRS: Start date of the internship.
    end_date date NULL, -- SRS: End date of the internship.
    total_days integer NULL -- SRS: Total number of days calculated automatically.
);
CREATE INDEX idx_internship_request_student_id ON INTERNSHIP_REQUEST(student_id);
CREATE INDEX idx_internship_request_company_id ON INTERNSHIP_REQUEST(company_id);

-- Description: Stores information about placement drives conducted by companies.
CREATE TABLE PLACEMENT_DRIVE (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each placement drive.
    company_id uuid REFERENCES COMPANY(id) ON DELETE CASCADE, -- SRS: Reference to the company conducting the drive.
    drive_date date NOT NULL, -- SRS: Date of the placement drive.
    venue string NOT NULL, -- SRS: Venue of the placement drive.
    criteria string NULL -- SRS: Criteria for selection during the drive.
);
CREATE INDEX idx_placement_drive_company_id ON PLACEMENT_DRIVE(company_id);

-- Description: Stores job postings made by companies.
CREATE TABLE JOB_POSTING (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each job posting.
    company_id uuid REFERENCES COMPANY(id) ON DELETE CASCADE, -- SRS: Reference to the company making the job posting.
    job_title string NOT NULL, -- SRS: Title of the job being posted.
    job_description string NOT NULL, -- SRS: Description of the job.
    posting_date date NOT NULL, -- SRS: Date when the job was posted.
    application_deadline date NOT NULL -- SRS: Deadline for applications.
);
CREATE INDEX idx_job_posting_company_id ON JOB_POSTING(company_id);

-- Description: Details the recruitment process for job postings.
CREATE TABLE RECRUITMENT_PROCESS (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each recruitment process.
    job_posting_id uuid REFERENCES JOB_POSTING(id) ON DELETE CASCADE, -- SRS: Reference to the job posting associated with the recruitment process.
    selection_criteria string NOT NULL, -- SRS: Criteria for selecting candidates.
    process_steps string NOT NULL -- SRS: Steps involved in the recruitment process.
);
CREATE INDEX idx_recruitment_process_job_posting_id ON RECRUITMENT_PROCESS(job_posting_id);

-- Description: Stores reports generated for placement analysis.
CREATE TABLE PLACEMENT_ANALYSIS_REPORT (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each placement analysis report.
    report_date date NOT NULL, -- SRS: Date when the report was generated.
    report_details string NOT NULL -- SRS: Details of the placement analysis report.
);
CREATE INDEX idx_placement_analysis_report_date ON PLACEMENT_ANALYSIS_REPORT(report_date);

-- Description: Tracks the approval status of companies added by students.
CREATE TABLE STUDENT_COMPANY_APPROVAL (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each approval record.
    student_id uuid REFERENCES STUDENT(id) ON DELETE CASCADE, -- SRS: Reference to the student who added the company.
    company_id uuid REFERENCES COMPANY(id) ON DELETE CASCADE, -- SRS: Reference to the company added by the student.
    approval_status enum CHECK (approval_status IN ('PENDING', 'APPROVED', 'REJECTED')), -- SRS: Current approval status of the company.
    approval_date date NULL -- SRS: Date when the approval status was updated.
);
CREATE INDEX idx_student_company_approval_student_id ON STUDENT_COMPANY_APPROVAL(student_id);
CREATE INDEX idx_student_company_approval_company_id ON STUDENT_COMPANY_APPROVAL(company_id);

-- Description: Table to store faculty member details.
CREATE TABLE faculty (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each faculty member.
    name string NOT NULL, -- SRS: Name of the faculty member.
    email string UNIQUE NOT NULL, -- SRS: Email address of the faculty member.
    department string NOT NULL -- SRS: Department of the faculty member.
);
CREATE INDEX idx_faculty_email ON faculty(email);

-- Description: Table to store research contributions by faculty.
CREATE TABLE research_contribution (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each research contribution.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member contributing.
    contribution_type enum NOT NULL CHECK (contribution_type IN ('Paper', 'Book Review', 'Case Review', 'Case Study', 'Research Monograph', 'Conference Proceedings', 'Working Paper', 'Industry Report')), -- SRS: Type of research contribution.
    title string NOT NULL, -- SRS: Title of the research contribution.
    publication_date date NOT NULL, -- SRS: Date of publication.
    details string NULL -- SRS: Additional details about the contribution.
);
CREATE INDEX idx_research_contribution_faculty_id ON research_contribution(faculty_id);

-- Description: Table to manage research projects.
CREATE TABLE research_project (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each research project.
    project_name string NOT NULL, -- SRS: Name of the research project.
    budget decimal NOT NULL CHECK (budget >= 0), -- SRS: Budget allocated for the project.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member managing the project.
    status enum NOT NULL CHECK (status IN ('Proposed', 'Approved', 'In Progress', 'Completed')), -- SRS: Current status of the research project.
    start_date date NOT NULL, -- SRS: Start date of the project.
    end_date date NULL -- SRS: End date of the project.
);
CREATE INDEX idx_research_project_faculty_id ON research_project(faculty_id);

-- Description: Table to store research events attended by faculty.
CREATE TABLE research_event (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each research event.
    event_name string NOT NULL, -- SRS: Name of the research event.
    event_date date NOT NULL, -- SRS: Date of the event.
    location string NOT NULL, -- SRS: Location of the event.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member attending the event.
    participation_type enum NOT NULL CHECK (participation_type IN ('Attended', 'Presented', 'Organized')) -- SRS: Type of participation in the event.
);
CREATE INDEX idx_research_event_faculty_id ON research_event(faculty_id);

-- Description: Table to store publications by faculty.
CREATE TABLE publication (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each publication.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member who published.
    title string NOT NULL, -- SRS: Title of the publication.
    publication_type enum NOT NULL CHECK (publication_type IN ('Journal', 'Conference', 'Book', 'Report')), -- SRS: Type of publication.
    publication_date date NOT NULL -- SRS: Date of publication.
);
CREATE INDEX idx_publication_faculty_id ON publication(faculty_id);

-- Description: Table to store conferences attended by faculty.
CREATE TABLE conference (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each conference.
    conference_name string NOT NULL, -- SRS: Name of the conference.
    conference_date date NOT NULL, -- SRS: Date of the conference.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member attending the conference.
    role enum NOT NULL CHECK (role IN ('Attendee', 'Speaker', 'Organizer')) -- SRS: Role of the faculty member in the conference.
);
CREATE INDEX idx_conference_faculty_id ON conference(faculty_id);

-- Description: Table to store workshops attended by faculty.
CREATE TABLE workshop (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each workshop.
    workshop_name string NOT NULL, -- SRS: Name of the workshop.
    workshop_date date NOT NULL, -- SRS: Date of the workshop.
    faculty_id uuid NOT NULL REFERENCES faculty(id), -- SRS: Reference to the faculty member attending the workshop.
    role enum NOT NULL CHECK (role IN ('Attendee', 'Facilitator')) -- SRS: Role of the faculty member in the workshop.
);
CREATE INDEX idx_workshop_faculty_id ON workshop(faculty_id);

-- Description: Stores categories for complaints.
CREATE TABLE complaint_category (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each complaint category.
    name string NOT NULL, -- SRS: Name of the complaint category.
    description string NULL, -- SRS: Description of the complaint category.
    escalation_days integer NOT NULL CHECK (escalation_days >= 0), -- SRS: Number of days for escalation as per SRS.
    escalation_level_1 string NOT NULL, -- SRS: Details for escalation level 1.
    escalation_level_2 string NULL -- SRS: Details for escalation level 2.
);
CREATE INDEX idx_complaint_category_name ON complaint_category(name);

-- Description: Stores individual complaints submitted by students.
CREATE TABLE complaint (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each complaint.
    category_id uuid NOT NULL REFERENCES complaint_category(id), -- SRS: Foreign key linking to the complaint category.
    student_id string NOT NULL, -- SRS: Identifier for the student submitting the complaint.
    description string NOT NULL, -- SRS: Detailed description of the complaint.
    status string NOT NULL CHECK (status IN ('Pending', 'Resolved', 'Escalated')), -- SRS: Current status of the complaint.
    created_at timestamp DEFAULT CURRENT_TIMESTAMP, -- SRS: Timestamp when the complaint was created.
    updated_at timestamp DEFAULT CURRENT_TIMESTAMP -- SRS: Timestamp when the complaint was last updated.
);
CREATE INDEX idx_complaint_student_id ON complaint(student_id);

-- Description: Stores standard reply templates for complaints.
CREATE TABLE reply_template (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each reply template.
    category_id uuid NOT NULL REFERENCES complaint_category(id), -- SRS: Foreign key linking to the complaint category.
    template string NOT NULL, -- SRS: The content of the reply template.
    is_standard boolean DEFAULT TRUE -- SRS: Indicates if the template is a standard reply.
);
CREATE INDEX idx_reply_template_category_id ON reply_template(category_id);

-- Description: Logs telephonic queries made by students.
CREATE TABLE telephonic_query (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each telephonic query.
    student_id string NOT NULL, -- SRS: Identifier for the student making the query.
    query string NOT NULL, -- SRS: Content of the telephonic query.
    logged_at timestamp DEFAULT CURRENT_TIMESTAMP -- SRS: Timestamp when the query was logged.
);
CREATE INDEX idx_telephonic_query_student_id ON telephonic_query(student_id);

-- Description: Stores alerts sent to students.
CREATE TABLE alert (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each alert.
    message string NOT NULL, -- SRS: Content of the alert message.
    recipient string NOT NULL, -- SRS: Recipient of the alert.
    medium string NOT NULL CHECK (medium IN ('Email', 'SMS')), -- SRS: Medium through which the alert is sent.
    sent_at timestamp DEFAULT CURRENT_TIMESTAMP -- SRS: Timestamp when the alert was sent.
);
CREATE INDEX idx_alert_recipient ON alert(recipient);

-- Description: Table to store journal vouchers.
CREATE TABLE journal_voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each journal voucher.
    voucher_type string NOT NULL, -- SRS: Type of the journal voucher (e.g., Journal, Party).
    created_at date NOT NULL, -- SRS: Date when the voucher was created.
    created_by string NOT NULL, -- SRS: User who created the voucher.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the voucher.
    description string NULL -- SRS: Description of the voucher.
);
CREATE INDEX idx_journal_voucher_created_at ON journal_voucher(created_at);

-- Description: Table to store expense vouchers.
CREATE TABLE expense_voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each expense voucher.
    journal_voucher_id uuid NOT NULL REFERENCES journal_voucher(id), -- SRS: Reference to the associated journal voucher.
    expense_type string NOT NULL, -- SRS: Type of expense being recorded.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the expense.
    created_at date NOT NULL, -- SRS: Date when the expense voucher was created.
    created_by string NOT NULL -- SRS: User who created the expense voucher.
);
CREATE INDEX idx_expense_voucher_created_at ON expense_voucher(created_at);

-- Description: Table to store payment vouchers.
CREATE TABLE payment_voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each payment voucher.
    journal_voucher_id uuid NOT NULL REFERENCES journal_voucher(id), -- SRS: Reference to the associated journal voucher.
    payment_method string NOT NULL, -- SRS: Method of payment used.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the payment.
    created_at date NOT NULL, -- SRS: Date when the payment voucher was created.
    created_by string NOT NULL -- SRS: User who created the payment voucher.
);
CREATE INDEX idx_payment_voucher_created_at ON payment_voucher(created_at);

-- Description: Table to store receipt vouchers.
CREATE TABLE receipt_voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each receipt voucher.
    journal_voucher_id uuid NOT NULL REFERENCES journal_voucher(id), -- SRS: Reference to the associated journal voucher.
    receipt_type string NOT NULL, -- SRS: Type of receipt being recorded.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the receipt.
    created_at date NOT NULL, -- SRS: Date when the receipt voucher was created.
    created_by string NOT NULL -- SRS: User who created the receipt voucher.
);
CREATE INDEX idx_receipt_voucher_created_at ON receipt_voucher(created_at);

-- Description: Table to store debit and credit notes.
CREATE TABLE debit_credit_note (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each debit/credit note.
    journal_voucher_id uuid NOT NULL REFERENCES journal_voucher(id), -- SRS: Reference to the associated journal voucher.
    note_type string NOT NULL, -- SRS: Type of note (Debit or Credit).
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the note.
    created_at date NOT NULL, -- SRS: Date when the note was created.
    created_by string NOT NULL -- SRS: User who created the note.
);
CREATE INDEX idx_debit_credit_note_created_at ON debit_credit_note(created_at);

-- Description: Table to store invoices.
CREATE TABLE invoice (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each invoice.
    invoice_number string NOT NULL, -- SRS: Unique invoice number.
    customer_id uuid NOT NULL REFERENCES customer(id), -- SRS: Reference to the customer associated with the invoice.
    total_amount decimal NOT NULL CHECK (total_amount >= 0), -- SRS: Total amount of the invoice.
    created_at date NOT NULL, -- SRS: Date when the invoice was created.
    created_by string NOT NULL -- SRS: User who created the invoice.
);
CREATE INDEX idx_invoice_created_at ON invoice(created_at);

-- Description: Table to store customer details.
CREATE TABLE customer (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each customer.
    name string NOT NULL, -- SRS: Name of the customer.
    email string NULL, -- SRS: Email address of the customer.
    phone string NULL -- SRS: Phone number of the customer.
);
CREATE INDEX idx_customer_name ON customer(name);

-- Description: Table to store supplier details.
CREATE TABLE supplier (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each supplier.
    name string NOT NULL, -- SRS: Name of the supplier.
    email string NULL, -- SRS: Email address of the supplier.
    phone string NULL -- SRS: Phone number of the supplier.
);
CREATE INDEX idx_supplier_name ON supplier(name);

-- Description: Table to store bank reconciliation details.
CREATE TABLE bank_reconciliation (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each bank reconciliation.
    reconciliation_date date NOT NULL, -- SRS: Date of the bank reconciliation.
    total_deposits decimal NOT NULL CHECK (total_deposits >= 0), -- SRS: Total deposits during the reconciliation period.
    total_withdrawals decimal NOT NULL CHECK (total_withdrawals >= 0), -- SRS: Total withdrawals during the reconciliation period.
    created_by string NOT NULL -- SRS: User who created the bank reconciliation.
);
CREATE INDEX idx_bank_reconciliation_date ON bank_reconciliation(reconciliation_date);

-- Description: Table to store budget details.
CREATE TABLE budget (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each budget.
    budget_type string NOT NULL, -- SRS: Type of budget (e.g., Operational, Capex).
    allocated_amount decimal NOT NULL CHECK (allocated_amount >= 0), -- SRS: Total amount allocated for the budget.
    spent_amount decimal NOT NULL CHECK (spent_amount >= 0), -- SRS: Total amount spent from the budget.
    created_at date NOT NULL, -- SRS: Date when the budget was created.
    created_by string NOT NULL -- SRS: User who created the budget.
);
CREATE INDEX idx_budget_created_at ON budget(created_at);

-- Description: Table to store audit report details.
CREATE TABLE audit_report (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each audit report.
    report_type string NOT NULL, -- SRS: Type of audit report generated.
    generated_at date NOT NULL, -- SRS: Date when the audit report was generated.
    generated_by string NOT NULL -- SRS: User who generated the audit report.
);
CREATE INDEX idx_audit_report_generated_at ON audit_report(generated_at);

-- Description: Table to store purchase vouchers.
CREATE TABLE purchase_voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each purchase voucher.
    journal_voucher_id uuid NOT NULL REFERENCES journal_voucher(id), -- SRS: Reference to the associated journal voucher.
    supplier_id uuid NOT NULL REFERENCES supplier(id), -- SRS: Reference to the supplier associated with the purchase.
    amount decimal NOT NULL CHECK (amount >= 0), -- SRS: Total amount of the purchase.
    created_at date NOT NULL, -- SRS: Date when the purchase voucher was created.
    created_by string NOT NULL -- SRS: User who created the purchase voucher.
);
CREATE INDEX idx_purchase_voucher_created_at ON purchase_voucher(created_at);

-- Description: Stores all types of vouchers including journal, expense, payment, receipt, and debit/credit notes.
CREATE TABLE voucher (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each voucher (SRS 37.3.1)
    type varchar(50) NOT NULL, -- SRS: Type of voucher (SRS 37.3.1)
    created_date date NOT NULL, -- SRS: Date when the voucher was created (SRS 37.3.1)
    voucher_date date NOT NULL, -- SRS: Date of the transaction related to the voucher (SRS 37.3.1)
    status varchar(20) CHECK (status IN ('draft', 'submitted', 'approved', 'rejected')), -- SRS: Current status of the voucher (SRS 37.1.6)
    created_by uuid NOT NULL, -- SRS: Identifier of the employee who created the voucher (SRS 37.3.1)
    approved_by uuid NULL -- SRS: Identifier of the employee who approved the voucher (SRS 37.3.1)
);
CREATE INDEX idx_voucher_type ON voucher(type);
CREATE INDEX idx_voucher_status ON voucher(status);

-- Description: Stores employee details who can create and approve vouchers.
CREATE TABLE employee (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each employee (SRS 37.2.2)
    name varchar(100) NOT NULL, -- SRS: Full name of the employee (SRS 37.2.2)
    email varchar(100) NOT NULL UNIQUE, -- SRS: Email address of the employee (SRS 37.2.3)
    phone varchar(15) NULL -- SRS: Contact number of the employee (SRS 37.2.3)
);
CREATE INDEX idx_employee_email ON employee(email);

-- Description: Stores generated financial reports.
CREATE TABLE report (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each report (SRS 37.8.1)
    report_type varchar(50) NOT NULL, -- SRS: Type of report generated (SRS 37.8.1)
    generated_date date NOT NULL, -- SRS: Date when the report was generated (SRS 37.8.1)
    generated_by uuid NOT NULL -- SRS: Identifier of the employee who generated the report (SRS 37.8.1)
);
CREATE INDEX idx_report_type ON report(report_type);

-- Description: Stores employee advance requests.
CREATE TABLE advance (
    id uuid PRIMARY KEY, -- SRS: Unique identifier for each advance request (SRS 37.2.1)
    employee_id uuid NOT NULL, -- SRS: Identifier of the employee requesting the advance (SRS 37.2.1)
    amount decimal(10,2) NOT NULL CHECK (amount > 0), -- SRS: Amount of the advance requested (SRS 37.2.1)
    request_date date NOT NULL, -- SRS: Date when the advance was requested (SRS 37.2.1)
    status varchar(20) CHECK (status IN ('pending', 'approved', 'rejected')) -- SRS: Current status of the advance request (SRS 37.2.1)
);
CREATE INDEX idx_advance_employee_id ON advance(employee_id);
CREATE INDEX idx_advance_status ON advance(status);

